25	export function claimOffice(input: any): unknown {
26	  const results: { premium: number }[] = [];
27	  let quoteIndex = 0;
28	
29	  for (const step of input.steps) {
30	    const items = step.items;
31	    let itemsTotal = 0;
32	    let policyBase = 0;
33	
34	    const typeCounts: Record<string, number> = {};
35	    for (const item of items) {
36	      itemsTotal += calculateItemPremium(item);
37	      policyBase += BASE_PREMIUMS[item.type];
38	      typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
39	    }
40	
41	    for (const type in typeCounts) {
42	      if (typeCounts[type] === 3) {
43	        itemsTotal = itemsTotal - (3 * BASE_PREMIUMS[type]) + BLOCK_OF_THREE_PRICE;
44	      }
45	    }
46	
47	    let policyModifier = 0;
48	    if (input.customer.yearsWithMHPCO >= 2) {
49	      policyModifier -= policyBase * 0.2;
50	    }
51	    policyModifier += policyBase * 0.1;
52	    if (quoteIndex > 0) {
53	      policyModifier -= policyBase * 0.15;
54	    }
55	
56	    const premium = Math.ceil(itemsTotal + policyModifier + PROCESSING_FEE);
57	    results.push({ premium });
58	    quoteIndex++;
59	  }
60	
61	  return { results };
62	}
